import { useSite } from "@rspress/core/runtime";
import { useCallback, useLayoutEffect } from "react";
import { useMediaQuery } from "./useMediaQuery.js";
import { useStorageValue } from "./useStorageValue.js";
const APPEARANCE_KEY = 'rspress-theme-appearance';
const MEDIA_QUERY = '(prefers-color-scheme: dark)';
const getSystemTheme = (prefersDark)=>prefersDark ? 'dark' : 'light';
const getStoredThemeConfig = (theme, prefersDark)=>{
    const systemTheme = getSystemTheme(prefersDark);
    return theme === systemTheme ? 'auto' : theme;
};
const getResolvedTheme = (config, prefersDark)=>'auto' === config ? getSystemTheme(prefersDark) : config;
const applyThemeToDOM = (theme)=>{
    if (!document?.documentElement) return;
    const root = document.documentElement;
    root.classList.toggle('dark', 'dark' === theme);
    root.classList.toggle('rp-dark', 'dark' === theme);
    root.style.colorScheme = theme;
};
function useThemeState() {
    const { site } = useSite();
    const disableDarkMode = false === site.themeConfig.darkMode;
    const prefersDark = useMediaQuery(MEDIA_QUERY);
    const [storedConfig, setStoredConfig] = useStorageValue(APPEARANCE_KEY, 'auto');
    const theme = disableDarkMode ? 'light' : getResolvedTheme(storedConfig, prefersDark);
    const setTheme = useCallback((value)=>{
        if (disableDarkMode) return;
        setStoredConfig(getStoredThemeConfig(value, prefersDark));
        applyThemeToDOM(value);
    }, [
        disableDarkMode,
        prefersDark,
        setStoredConfig
    ]);
    useLayoutEffect(()=>{
        applyThemeToDOM(theme);
    }, [
        theme
    ]);
    return [
        theme,
        setTheme
    ];
}
export { getResolvedTheme, getStoredThemeConfig, useThemeState };
